from pathlib import Path
from collections import defaultdict
import bisect, math
RAD=255
OFF1=5
OFF2=2
INTOFF=9
LITSIZE=4

data=Path('/app/data.txt').read_bytes()
n=len(data)

# enumerate all used contexts exactly
ctxs={1,8}
def add_int_ctxs(max_val,tmp,ctx):
    base=ctx*99
    v=max_val+(1<<tmp)
    h=v.bit_length()-1
    for t in range(tmp+1,h+2):
        ctxs.add(base+t)
    ctxs.add(base)
add_int_ctxs(n,INTOFF,0)
add_int_ctxs(n-1,OFF1,2)
add_int_ctxs(n-1,OFF2,3)
max_mag=max(max((b for b in data if b<=127), default=0), max((256-b for b in data if b>127), default=0))
add_int_ctxs(max_mag,LITSIZE,9)
ctxs=sorted(ctxs)
idx={c:i for i,c in enumerate(ctxs)}
M=len(ctxs)
print('contexts',M,'max_mag',max_mag)

class Model:
    __slots__=('a','b')
    def __init__(self,a=None,b=None):
        self.a=[0]*M if a is None else a[:] 
        self.b=[0]*M if b is None else b[:] 
    def bit_cost(self,bit,ctx):
        i=idx[ctx]
        c0=self.a[i]; c1=self.b[i]
        return math.log2((c0+c1+2)/((c1 if bit else c0)+1))
    def upd(self,bit,ctx):
        i=idx[ctx]
        if bit: self.b[i]+=1
        else: self.a[i]+=1
    def enc_bit(self,bit,ctx):
        c=self.bit_cost(bit,ctx)
        self.upd(bit,ctx)
        return c

def int_cost(val,tmp,ctx,m,update=False):
    v=val+(1<<tmp); h=v.bit_length()-1; base=ctx*99; cur=tmp; cost=0.0
    for _ in range(h-tmp):
        cur+=1
        cost += m.enc_bit(0,cur+base) if update else m.bit_cost(0,cur+base)
    cur+=1
    cost += m.enc_bit(1,cur+base) if update else m.bit_cost(1,cur+base)
    for j in range(h-1,-1,-1):
        bit=(v>>j)&1
        cost += m.enc_bit(bit,base) if update else m.bit_cost(bit,base)
    return cost

def op_cost(op,m,update=False):
    if op[0]=='lit':
        ch=op[1]
        c=(m.enc_bit(0,1) if update else m.bit_cost(0,1))
        sign=1 if ch>127 else 0
        c += m.enc_bit(sign,8) if update else m.bit_cost(sign,8)
        c += int_cost(256-ch if ch>127 else ch,LITSIZE,9,m,update)
        return c
    _,off,L=op
    c=(m.enc_bit(1,1) if update else m.bit_cost(1,1))
    c += int_cost(off-1,OFF1,2,m,update)
    c += int_cost(L-1,OFF2,3,m,update)
    return c

def int_bitlen(val,tmp):
    v=val+(1<<tmp); h=v.bit_length()-1
    return (h-tmp)+1+h

def rough_cost(op):
    if op[0]=='lit':
        ch=op[1]
        return 2 + int_bitlen(256-ch if ch>127 else ch,LITSIZE)
    _,off,L=op
    return 1 + int_bitlen(off-1,OFF1) + int_bitlen(L-1,OFF2)

positions=defaultdict(list)
for i in range(n-3): positions[data[i:i+4]].append(i)
all_cands=[[] for _ in range(n)]
for i in range(n):
    if i+4>n: continue
    lst=positions[data[i:i+4]]
    k=bisect.bisect_left(lst,i)
    prev=lst[:k]
    picks=[]
    picks.extend(prev[max(0,len(prev)-500):])
    if len(prev)>500:
        step=max(1,len(prev)//150)
        picks.extend(prev[::step])
    seen=set(); uniq=[]
    for j in picks:
        if j not in seen:
            seen.add(j); uniq.append(j)
    cand=[]
    for j in uniq:
        off=i-j
        l=0; maxl=n-i
        while l<maxl and data[i+l]==data[i+l-off]: l+=1
        if l>=2:
            lens={2,3,4,5,6,7,8,10,12,16,24,32,48,64,96,128,192,256,384,512,768,1024,1536,l}
            for t in range(2,13):
                x=(1<<t)-1
                if x<=l: lens.add(x)
                if x+1<=l: lens.add(x+1)
            for L in lens:
                if 2<=L<=l: cand.append(('mat',off,L))
    if cand:
        best_by_len={}
        for op in cand:
            L=op[2]; c=rough_cost(op)
            if L not in best_by_len or c<best_by_len[L][0]: best_by_len[L]=(c,op)
        arr=sorted((L,c,op) for L,(c,op) in best_by_len.items())
        keep=[]; minc=10**9
        for L,c,op in reversed(arr):
            if c<minc:
                keep.append(op); minc=c
        all_cands[i]=list(reversed(keep))

best=[0.0]*(n+1); choice=[None]*(n+1)
for i in range(n-1,-1,-1):
    lit=('lit',data[i]); bc=rough_cost(lit)+best[i+1]; ch=lit
    for op in all_cands[i]:
        v=rough_cost(op)+best[i+op[2]]
        if v<bc: bc=v; ch=op
    best[i]=bc; choice[i]=ch
ops=[]; i=0
while i<n:
    op=choice[i]; ops.append(op); i += 1 if op[0]=='lit' else op[2]

for it in range(6):
    snap_a=[[0]*M for _ in range(n+1)]
    snap_b=[[0]*M for _ in range(n+1)]
    m=Model()
    int_cost(len(ops),INTOFF,0,m,update=True)
    pos=0
    for op in ops:
        end=pos + (1 if op[0]=='lit' else op[2])
        sa=m.a[:] ; sb=m.b[:]
        for k in range(pos,end):
            snap_a[k]=sa; snap_b[k]=sb
        op_cost(op,m,update=True)
        pos=end
    snap_a[n]=m.a[:] ; snap_b[n]=m.b[:]

    dp=[0.0]*(n+1); chs=[None]*(n+1)
    for i in range(n-1,-1,-1):
        lit=('lit',data[i])
        base=Model(snap_a[i],snap_b[i])
        bc=op_cost(lit,base,update=False)+dp[i+1]; ch=lit
        for op in all_cands[i]:
            base2=Model(snap_a[i],snap_b[i])
            v=op_cost(op,base2,update=False)+dp[i+op[2]]
            if v<bc: bc=v; ch=op
        dp[i]=bc; chs[i]=ch
    ops=[]; i=0
    while i<n:
        op=chs[i]; ops.append(op); i += 1 if op[0]=='lit' else op[2]
    seq=[]
    def eb(b,c): seq.append((c,b))
    def ei(val,tmp,ctx):
        v=val+(1<<tmp); h=v.bit_length()-1; base=ctx*99; cur=tmp
        for _ in range(h-tmp): cur+=1; eb(0,cur+base)
        cur+=1; eb(1,cur+base)
        for j in range(h-1,-1,-1): eb((v>>j)&1,base)
    ei(len(ops),INTOFF,0)
    for op in ops:
        if op[0]=='lit':
            ch=op[1]; eb(0,1); eb(1 if ch>127 else 0,8); ei(256-ch if ch>127 else ch,LITSIZE,9)
        else:
            _,off,L=op; eb(1,1); ei(off-1,OFF1,2); ei(L-1,OFF2,3)
    cc=[0]*1000000; r=1; steps=[]
    for ctx,b in seq:
        ren=r<RAD; R=r*RAD if ren else r
        c0=cc[ctx*2]; c1=cc[ctx*2+1]
        split=R*(c0+1)//(c0+c1+2)
        r=split if b==0 else R-split
        steps.append((ren,split,b))
        cc[ctx*2+b]+=1
    f=0; digs=[]
    for ren,split,b in reversed(steps):
        F=f+split*b
        if ren:
            f,d=divmod(F,RAD); digs.append(d+1)
        else:
            f=F
    assert f==0
    enc=bytes(reversed(digs))
    print('iter',it,'ops',len(ops),'enc',len(enc),'matches',sum(1 for x in ops if x[0]=='mat'))

Path('/app/data.comp').write_bytes(enc)
